            aOrbiterD = ((aOrbiterD + aOrbiterE) + 0xAC2C8A2CA6244ADCULL) + aPhaseBOrbiterUpdateSaltE[(((31U - aIndex) + 29U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 0xBA2CE91F8EB73724ULL;
